good-example.code-block:
import io.mongock.api.annotations.ChangeUnit;
import io.mongock.api.annotations.Execution;
import io.mongock.api.annotations.RollbackExecution;
import org.springframework.data.mongodb.core.MongoTemplate;
import org.springframework.data.mongodb.core.query.Query;
import org.springframework.data.mongodb.core.query.Update;

import static org.springframework.data.mongodb.core.query.Criteria.where;

@ChangeUnit(id = "orders-add-status", order = "001", author = "platform")
public class OrdersAddStatusChange {

    @Execution
    public void execute(MongoTemplate mongoTemplate) {
        Query missingStatus = Query.query(where("status").exists(false));
        Update setPending = new Update().set("status", "PENDING");
        mongoTemplate.updateMulti(missingStatus, setPending, "orders");
    }

    @RollbackExecution
    public void rollback(MongoTemplate mongoTemplate) {
        Query pendingFromMigration = Query.query(where("status").is("PENDING"));
        Update removeStatus = new Update().unset("status");
        mongoTemplate.updateMulti(pendingFromMigration, removeStatus, "orders");
    }
}

bad-example.code-block:
// Bad: repository/domain coupling makes old migrations fragile when OrderDocument changes
@ChangeUnit(id = "orders-add-status", order = "001", author = "platform")
class OrdersAddStatusChange {
    @Execution
    void execute(OrderRepository repository) {
        repository.findAll().forEach(order -> repository.save(order.withStatus("PENDING")));
    }
}

good-example.code-block:
@SpringBootTest
@Testcontainers
class MongockMigrationTest {

    @Container
    static MongoDBContainer mongo = new MongoDBContainer("mongo:7.0");

    @DynamicPropertySource
    static void mongoProperties(DynamicPropertyRegistry registry) {
        registry.add("spring.data.mongodb.uri", mongo::getReplicaSetUrl);
    }

    @Autowired MongoTemplate mongoTemplate;

    @Test
    void appliesOrderStatusMigration() {
        assertThat(mongoTemplate.findAll(Document.class, "orders"))
            .allSatisfy(order -> assertThat(order).containsKey("status"));
    }
}
